<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> get_info</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F9E2AF;font-style:italic;">InitializeResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
